SELECT id, check_no, check_type, scope_grain_ids, scope_position_ids, operator_ids, deadline, status, total_items, checked_items, match_rate, report_url, create_user_id, create_time, complete_time FROM t_inventory_check WHERE 1=1
AND status = #{status}
AND check_type = #{checkType}
ORDER BY create_time DESC
